import{apiJson}from'./services/http-131d1b127e6b.js';export async function suggestValuations(query){const{res,data}=await apiJson('/api/valuations/suggest',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({query})});if(!res.ok)throw new Error('Valuation suggest failed');return data;}window.suggestValuations=suggestValuations;export function promptSuggest(){const q=prompt('Enter item name to get valuation suggestions:');if(!q)return;suggestValuations(q).then(r=>{console.log('Suggestions:',r);alert('Suggestions logged to console');}).catch(e=>{console.error(e);alert('Suggestion request failed');});}window.promptSuggestValuations=promptSuggest;